package main

import (
	"context"
	"fmt"
	"regexp"
	"strings"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
)

// MetadataValidator enforces strict metadata validation
type MetadataValidator struct {
	allowedKeys map[string]*regexp.Regexp
	maxValueLength int
}

// NewMetadataValidator creates validator with whitelist
func NewMetadataValidator() *MetadataValidator {
	return &MetadataValidator{
		allowedKeys: map[string]*regexp.Regexp{
			"authorization": regexp.MustCompile(`^Bearer [A-Za-z0-9-_\.]+$`),
			"x-request-id": regexp.MustCompile(`^[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}$`),
			"x-trace-id": regexp.MustCompile(`^[a-f0-9]{32}$`),
			"content-type": regexp.MustCompile(`^application/grpc`),
		},
		maxValueLength: 2048, // Prevent header bomb attacks
	}
}

// ValidateMetadata checks metadata against whitelist
func (v *MetadataValidator) ValidateMetadata(md metadata.MD) error {
	for key, values := range md {
		// Convert to lowercase for case-insensitive comparison
		key = strings.ToLower(key)

		// Skip internal gRPC metadata (starts with 'grpc-')
		if strings.HasPrefix(key, "grpc-") {
			continue
		}

		// Check if key is whitelisted
		pattern, allowed := v.allowedKeys[key]
		if !allowed {
			return status.Errorf(codes.InvalidArgument, 
				"forbidden metadata key: %s", key)
		}

		// Validate each value
		for _, value := range values {
			// Check length limit
			if len(value) > v.maxValueLength {
				return status.Errorf(codes.InvalidArgument,
					"metadata value exceeds max length (%d bytes)", v.maxValueLength)
			}

			// Validate against pattern
			if !pattern.MatchString(value) {
				return status.Errorf(codes.InvalidArgument,
					"metadata value for key '%s' doesn't match required pattern", key)
			}
		}
	}
	return nil
}

// UnaryServerInterceptor validates metadata for unary RPCs
func (v *MetadataValidator) UnaryServerInterceptor() grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler) (interface{}, error) {

		// Extract metadata from context
		md, ok := metadata.FromIncomingContext(ctx)
		if !ok {
			return nil, status.Error(codes.InvalidArgument, "missing metadata")
		}

		// Validate metadata
		if err := v.ValidateMetadata(md); err != nil {
			return nil, err
		}

		// Continue to next handler
		return handler(ctx, req)
	}
}

// StreamServerInterceptor validates metadata for streaming RPCs
func (v *MetadataValidator) StreamServerInterceptor() grpc.StreamServerInterceptor {
	return func(srv interface{}, ss grpc.ServerStream, info *grpc.StreamServerInfo,
		handler grpc.StreamHandler) error {

		// Extract metadata from stream context
		md, ok := metadata.FromIncomingContext(ss.Context())
		if !ok {
			return status.Error(codes.InvalidArgument, "missing metadata")
		}

		// Validate metadata
		if err := v.ValidateMetadata(md); err != nil {
			return err
		}

		// Continue to next handler
		return handler(srv, ss)
	}
}

// Usage example
func main() {
	validator := NewMetadataValidator()

	// Create gRPC server with validation interceptors
	server := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			validator.UnaryServerInterceptor(),
			// Add authentication interceptor after validation
		),
		grpc.ChainStreamInterceptor(
			validator.StreamServerInterceptor(),
		),
	)

	fmt.Println("gRPC server with metadata validation started")
}

const grpc = require('@grpc/grpc-js');
const jwt = require('jsonwebtoken');

/**
 * Secure authorization interceptor for Node.js gRPC server
 * Validates JWT tokens and prevents metadata injection attacks
 */
class AuthorizationInterceptor {
  constructor(jwtPublicKey, options = {}) {
    this.jwtPublicKey = jwtPublicKey;
    this.algorithm = options.algorithm || 'RS256';
    this.issuer = options.issuer || 'https://auth.example.com';
    this.audience = options.audience || 'grpc-api';
  }

  /**
   * Extract and validate authorization token from metadata
   */
  extractToken(metadata) {
    // Get authorization header from metadata
    const authHeader = metadata.get('authorization');

    if (!authHeader || authHeader.length === 0) {
      throw new Error('Missing authorization header');
    }

    // Extract Bearer token
    const token = authHeader[0];
    if (!token.startsWith('Bearer ')) {
      throw new Error('Invalid authorization format');
    }

    return token.substring(7); // Remove 'Bearer ' prefix
  }

  /**
   * Verify JWT token and extract claims
   */
  verifyToken(token) {
    try {
      const decoded = jwt.verify(token, this.jwtPublicKey, {
        algorithms: [this.algorithm],
        issuer: this.issuer,
        audience: this.audience,
        clockTolerance: 30 // Allow 30s clock skew
      });

      // Validate required claims
      if (!decoded.sub || !decoded.roles) {
        throw new Error('Missing required claims');
      }

      return {
        userId: decoded.sub,
        roles: decoded.roles,
        permissions: decoded.permissions || [],
        exp: decoded.exp
      };
    } catch (error) {
      throw new Error(`Token verification failed: ${error.message}`);
    }
  }

  /**
   * Check if user has required permissions for method
   */
  checkPermission(user, methodPath) {
    // Define method-to-permission mapping
    const permissionMap = {
      '/users.UserService/GetUser': ['users:read'],
      '/users.UserService/CreateUser': ['users:write', 'admin'],
      '/users.UserService/DeleteUser': ['users:delete', 'admin']
    };

    const requiredPerms = permissionMap[methodPath];
    if (!requiredPerms) {
      // Method not protected, allow access
      return true;
    }

    // Check if user has any of the required permissions
    return requiredPerms.some(perm => 
      user.permissions.includes(perm) || user.roles.includes(perm)
    );
  }

  /**
   * Create unary interceptor
   */
  createUnaryInterceptor() {
    return (methodDescriptor, call) => {
      const metadata = call.metadata;

      try {
        // CRITICAL: Never trust client metadata for authorization
        // Extract token from metadata
        const token = this.extractToken(metadata);

        // Verify token cryptographically
        const user = this.verifyToken(token);

        // Check method-level permissions
        const methodPath = methodDescriptor.path;
        if (!this.checkPermission(user, methodPath)) {
          const error = {
            code: grpc.status.PERMISSION_DENIED,
            message: 'Insufficient permissions for this operation'
          };
          call.sendStatus(error);
          return;
        }

        // Add verified user context (NOT from client metadata)
        // This creates new trusted metadata for downstream services
        const trustedMetadata = new grpc.Metadata();
        trustedMetadata.set('x-verified-user-id', user.userId);
        trustedMetadata.set('x-verified-roles', JSON.stringify(user.roles));

        // Store in call context for use by handlers
        call.metadata = trustedMetadata;

        // Continue to next interceptor/handler
        return call;

      } catch (error) {
        // Authentication/authorization failed
        const errorStatus = {
          code: grpc.status.UNAUTHENTICATED,
          message: error.message
        };
        call.sendStatus(errorStatus);
        return;
      }
    };
  }
}

// Usage example
const fs = require('fs');
const publicKey = fs.readFileSync('./jwt-public.pem', 'utf8');

const authInterceptor = new AuthorizationInterceptor(publicKey, {
  algorithm: 'RS256',
  issuer: 'https://auth.example.com',
  audience: 'grpc-api'
});

// Create gRPC server with authorization interceptor
const server = new grpc.Server({
  interceptors: [authInterceptor.createUnaryInterceptor()]
});

// WARNING: Never do this - trusting client metadata directly
// BAD EXAMPLE (vulnerable to injection):
// const userRole = metadata.get('x-user-role')[0]; // NEVER!
// if (userRole === 'admin') { /* grant access */ }

console.log('gRPC server started with secure authorization');
